t.script:
                (function () {
                    function initLocationPicker() {
                        var page = document.querySelector('.o_property_location_picker_page');
                        if (!page || typeof L === 'undefined') {
                            return;
                        }

                        var propertyId = page.dataset.propertyId;
                        var initialLat = parseFloat(page.dataset.latitude || '');
                        var initialLng = parseFloat(page.dataset.longitude || '');
                        var hasCoords = !isNaN(initialLat) && !isNaN(initialLng);
                        var defaultLat = hasCoords ? initialLat : -18.8792;
                        var defaultLng = hasCoords ? initialLng : 47.5079;

                        var latInput = document.getElementById('o_property_location_lat');
                        var lngInput = document.getElementById('o_property_location_lng');
                        var messageBox = document.getElementById('o_property_location_message');
                        var resultsBox = document.getElementById('o_property_location_results');

                        var map = L.map('o_property_location_map').setView([defaultLat, defaultLng], hasCoords ? 17 : 12);

                        L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
                            maxZoom: 19,
                            attribution: 'Tiles © Esri'
                        }).addTo(map);

                        var marker = L.marker([defaultLat, defaultLng], {draggable: true}).addTo(map);

                        function setPosition(lat, lng, zoom) {
                            lat = parseFloat(lat);
                            lng = parseFloat(lng);
                            marker.setLatLng([lat, lng]);
                            latInput.value = lat.toFixed(8);
                            lngInput.value = lng.toFixed(8);
                            if (zoom) {
                                map.setView([lat, lng], zoom);
                            }
                        }

                        setPosition(defaultLat, defaultLng, false);

                        map.on('click', function (ev) {
                            setPosition(ev.latlng.lat, ev.latlng.lng, false);
                        });

                        marker.on('dragend', function () {
                            var pos = marker.getLatLng();
                            setPosition(pos.lat, pos.lng, false);
                        });

                        async function searchAddress() {
                            var query = document.getElementById('o_property_location_search').value.trim();
                            resultsBox.innerHTML = '';
                            if (!query) {
                                return;
                            }
                            resultsBox.innerHTML = '
Recherche en cours...';
                            try {
                                var response = await fetch('https://nominatim.openstreetmap.org/search?format=json&limit=5&q=' + encodeURIComponent(query));
                                var data = await response.json();
                                resultsBox.innerHTML = '';
                                if (!data.length) {
                                    resultsBox.innerHTML = '
Aucun résultat trouvé.';
                                    return;
                                }
                                data.forEach(function (item) {
                                    var btn = document.createElement('button');
                                    btn.type = 'button';
                                    btn.className = 'list-group-item list-group-item-action';
                                    btn.textContent = item.display_name;
                                    btn.addEventListener('click', function () {
                                        setPosition(item.lat, item.lon, 17);
                                        resultsBox.innerHTML = '';
                                    });
                                    resultsBox.appendChild(btn);
                                });
                            } catch (err) {
                                resultsBox.innerHTML = '
Erreur pendant la recherche.';
                            }
                        }

                        document.getElementById('o_property_location_search_btn').addEventListener('click', searchAddress);
                        document.getElementById('o_property_location_search').addEventListener('keydown', function (ev) {
                            if (ev.key === 'Enter') {
                                ev.preventDefault();
                                searchAddress();
                            }
                        });

                        document.getElementById('o_property_location_save').addEventListener('click', async function () {
                            messageBox.innerHTML = '
Enregistrement en cours...';
                            try {
                                var response = await fetch('/property-location-picker/save', {
                                    method: 'POST',
                                    headers: {'Content-Type': 'application/json'},
                                    body: JSON.stringify({
                                        jsonrpc: '2.0',
                                        method: 'call',
                                        params: {
                                            property_id: propertyId,
                                            latitude: latInput.value,
                                            longitude: lngInput.value
                                        }
                                    })
                                });
                                var payload = await response.json();
                                var result = payload.result || {};
                                if (result.success) {
                                    messageBox.innerHTML = '
Localisation enregistrée. Tu peux fermer cette fenêtre puis actualiser la fiche bien.';
                                } else {
                                    messageBox.innerHTML = '
' + (result.message || 'Erreur inconnue.') + '';
                                }
                            } catch (err) {
                                messageBox.innerHTML = '
Impossible d’enregistrer la localisation.';
                            }
                        });

                        setTimeout(function () { map.invalidateSize(); }, 300);
                    }

                    if (document.readyState === 'loading') {
                        document.addEventListener('DOMContentLoaded', initLocationPicker);
                    } else {
                        initLocationPicker();
                    }
                })();
